import React from 'react';
import ConfidenceBar from './ConfidenceBar';
import './ResultDisplay.css';

/* Map raw keys like "50_GHS" → "GH₵ 50" */
function formatDenomination(raw) {
  if (!raw) return '';
  const num = raw.replace('_GHS', '').replace(' GHS', '');
  return `GH₵ ${num}`;
}

/* Confidence level label + colour */
function confidenceLevel(pct) {
  if (pct >= 90) return { label: 'Very High',  color: '#006B3F' };
  if (pct >= 75) return { label: 'High',        color: '#15803d' };
  if (pct >= 55) return { label: 'Moderate',    color: '#ca8a04' };
  return            { label: 'Low',          color: '#CE1126' };
}

function ResultDisplay({ result, loading }) {
  /* ── Loading skeleton ───────────────────────────────────────────────────── */
  if (loading) {
    return (
      <div className="result-card">
        <div className="result-card__header">
          <h3>Analysing Image&hellip;</h3>
        </div>
        <div className="result-card__body">
          <div className="skeleton skeleton-hero" />
          <div className="skeleton skeleton-line" style={{ width: '60%' }} />
          <div className="skeleton skeleton-line" style={{ width: '80%' }} />
          <div className="skeleton skeleton-line" style={{ width: '70%' }} />
          <div className="skeleton skeleton-line" style={{ width: '50%' }} />
        </div>
      </div>
    );
  }

  if (!result) return null;

  const { prediction, raw_key, confidence_percentage, all_predictions } = result;
  const displayDenom = formatDenomination(raw_key || prediction);
  const level        = confidenceLevel(confidence_percentage);

  return (
    <div className="result-card">
      {/* ── Header ──────────────────────────────────────────────────────────── */}
      <div className="result-card__header">
        <h3>Recognition Result</h3>
        <span className="result-tag" style={{ color: level.color, borderColor: level.color }}>
          {level.label} Confidence
        </span>
      </div>

      <div className="result-card__body">

        {/* ── Hero result ──────────────────────────────────────────────────── */}
        <div className="result-hero">
          <div className="result-note-wrap">
            <div className="result-note-icon">&#127981;</div>
            <div>
              <p className="result-label">Identified Denomination</p>
              <p className="result-denom">{displayDenom}</p>
            </div>
          </div>

          {/* Confidence ring */}
          <div className="result-ring-wrap">
            <svg className="result-ring" viewBox="0 0 80 80" width="80" height="80">
              <circle
                cx="40" cy="40" r="32"
                fill="none"
                stroke="#e2e8f0"
                strokeWidth="8"
              />
              <circle
                cx="40" cy="40" r="32"
                fill="none"
                stroke={level.color}
                strokeWidth="8"
                strokeLinecap="round"
                strokeDasharray={`${2 * Math.PI * 32}`}
                strokeDashoffset={`${2 * Math.PI * 32 * (1 - confidence_percentage / 100)}`}
                transform="rotate(-90 40 40)"
                style={{ transition: 'stroke-dashoffset 0.8s ease' }}
              />
              <text
                x="40" y="44"
                textAnchor="middle"
                fontSize="14"
                fontWeight="700"
                fill={level.color}
              >
                {confidence_percentage.toFixed(0)}%
              </text>
            </svg>
            <p className="result-ring-label">Confidence</p>
          </div>
        </div>

        {/* Divider */}
        <hr className="result-divider" />

        {/* ── All predictions ──────────────────────────────────────────────── */}
        <div className="result-all-header">
          <h4>All Denomination Probabilities</h4>
          <span className="result-count">{all_predictions.length} classes</span>
        </div>

        <div className="result-bars">
          {all_predictions.map((item, idx) => (
            <ConfidenceBar
              key={item.raw_key || item.denomination}
              denomination={formatDenomination(item.raw_key) || item.denomination}
              percentage={item.percentage}
              isTop={idx === 0}
              rank={idx + 1}
            />
          ))}
        </div>

        {/* ── Tip ─────────────────────────────────────────────────────────── */}
        {confidence_percentage < 70 && (
          <div className="result-tip">
            <strong>Tip:</strong> For better accuracy, ensure the note fills the frame, is well-lit,
            and the image is not blurry.
          </div>
        )}

      </div>
    </div>
  );
}

export default ResultDisplay;
